import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getUserTier, TIER_LEVELS } from '../hooks/useTierGate';
import useStripeCheckout from '../hooks/useStripeCheckout';
import { tokens } from '../styles/tokens';
import { AURA_TIERS, tierPrice, RENTAL_PRICING } from '../config/pricing';

const T = {
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  blue: tokens.color.blue, green: tokens.color.green, purple: tokens.color.purple,
  amber: tokens.color.amber, border: tokens.color.border,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

const DISMISS_PREFIX = 'aura_upsell_dismissed_';
const DISMISS_DURATION_MS = 24 * 60 * 60 * 1000; // 24 hours

/**
 * Contextual upsell presets. Each defines a message, CTA, and the tier needed.
 * Prices sourced from shared config/pricing.js
 */
const UPSELL_PRESETS = {
  realtime_signals: {
    message: 'Unlock real-time signals',
    detail: 'upgrade to Trader for live market data',
    tier: 'trader',
    color: T.green,
    price: tierPrice('trader'),
  },
  ml_analytics: {
    message: 'Access ML Analytics & AI scoring',
    detail: 'upgrade to Pro for machine learning insights',
    tier: 'pro',
    color: T.purple,
    price: tierPrice('pro'),
  },
  options_data: {
    message: 'Unlock full options chain data',
    detail: 'upgrade to Trader for options + Greeks',
    tier: 'trader',
    color: T.green,
    price: tierPrice('trader'),
  },
  more_bots: {
    message: 'Run more live bots',
    detail: 'upgrade to increase your bot limit',
    tier: 'pro',
    color: T.green,
    price: tierPrice('pro'),
  },
  more_strategies: {
    message: 'Unlock more strategies',
    detail: 'upgrade for full strategy catalogue access',
    tier: 'trader',
    color: T.blue,
    price: tierPrice('trader'),
  },
  more_alerts: {
    message: 'Need more alerts?',
    detail: 'upgrade for higher limits or unlimited alerts',
    tier: 'starter',
    color: T.blue,
    price: tierPrice('starter'),
  },
  drawing_tools: {
    message: 'Unlock drawing tools & comparison mode',
    detail: 'upgrade to Starter for charting extras',
    tier: 'starter',
    color: T.blue,
    price: tierPrice('starter'),
  },
  compute_credits: {
    message: 'Running low on compute credits',
    detail: 'buy more credits or upgrade for bonus credits',
    tier: 'pro',
    color: T.amber,
    price: tierPrice('pro'),
  },
  strategy_rentals: {
    message: 'Rent top-performing strategies',
    detail: `signal strategies from $${RENTAL_PRICING.signal.min}/mo`,
    tier: 'trader',
    color: T.green,
    price: `From $${RENTAL_PRICING.signal.min}/mo`,
  },
};

/**
 * Check if the dismiss cooldown is still active for this preset.
 */
function isDismissed(preset) {
  try {
    const ts = localStorage.getItem(DISMISS_PREFIX + preset);
    if (!ts) return false;
    return Date.now() - Number(ts) < DISMISS_DURATION_MS;
  } catch { return false; }
}

function setDismissed(preset) {
  try {
    localStorage.setItem(DISMISS_PREFIX + preset, String(Date.now()));
  } catch { /* silent */ }
}

/**
 * UpsellBanner - Slim contextual upgrade banner.
 *
 * Props:
 *   preset       - One of the UPSELL_PRESETS keys
 *   message      - Custom message override
 *   detail       - Custom detail override
 *   tier         - Custom tier override
 *   color        - Custom color override
 *   price        - Custom price override
 *   show         - External show control (default true)
 *   onUpgrade    - Optional callback on upgrade click
 */
export default function UpsellBanner({
  preset = 'realtime_signals',
  message: msgOverride,
  detail: detailOverride,
  tier: tierOverride,
  color: colorOverride,
  price: priceOverride,
  show: externalShow = true,
  onUpgrade,
}) {
  const nav = useNavigate();
  const { checkout, loading: checkoutLoading } = useStripeCheckout();
  const userTier = getUserTier();

  const config = UPSELL_PRESETS[preset] || UPSELL_PRESETS.realtime_signals;
  const requiredTier = tierOverride || config.tier;
  const color = colorOverride || config.color;
  const price = priceOverride || config.price;
  const msg = msgOverride || config.message;
  const detail = detailOverride || config.detail;

  // Already at or above required tier -- hide
  const alreadyHasTier = (TIER_LEVELS[userTier] ?? 0) >= (TIER_LEVELS[requiredTier] ?? 0);

  const [visible, setVisible] = useState(() => {
    if (!externalShow || alreadyHasTier) return false;
    return !isDismissed(preset);
  });

  // Update visibility when external show changes
  useEffect(() => {
    if (!externalShow || alreadyHasTier) {
      setVisible(false);
    } else if (!isDismissed(preset)) {
      setVisible(true);
    }
  }, [externalShow, alreadyHasTier, preset]);

  const dismiss = useCallback(() => {
    setDismissed(preset);
    setVisible(false);
  }, [preset]);

  const handleUpgrade = useCallback(() => {
    if (onUpgrade) {
      onUpgrade();
    } else {
      checkout(requiredTier);
    }
  }, [onUpgrade, checkout, requiredTier]);

  if (!visible) return null;

  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap',
      padding: '10px 16px', borderRadius: 10, marginBottom: 12,
      background: `linear-gradient(90deg, ${color}08, ${color}04)`,
      border: `1px solid ${color}20`,
      backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)',
      fontFamily: T.sans,
    }}>
      {/* Arrow / sparkle icon */}
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2"
        style={{ flexShrink: 0, opacity: 0.8 }}>
        <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" />
      </svg>

      {/* Message */}
      <div style={{ flex: 1, minWidth: 200 }}>
        <span style={{ fontSize: 13, fontWeight: 600, color: T.text }}>
          {msg}
        </span>
        <span style={{ fontSize: 13, color: T.textSec }}>
          {' -- '}{detail}
        </span>
        {price && (
          <span style={{
            fontSize: 11, fontFamily: T.mono, color, fontWeight: 700,
            marginLeft: 8, padding: '1px 6px', borderRadius: 4,
            background: `${color}10`, border: `1px solid ${color}18`,
          }}>
            {price}
          </span>
        )}
      </div>

      {/* Upgrade CTA */}
      <button
        onClick={handleUpgrade}
        disabled={checkoutLoading}
        style={{
          padding: '6px 16px', borderRadius: 6, fontSize: 12, fontWeight: 700,
          fontFamily: T.mono, color: '#fff', border: 'none', cursor: 'pointer',
          background: color, whiteSpace: 'nowrap',
          opacity: checkoutLoading ? 0.7 : 1,
          transition: 'opacity 0.15s',
        }}
        onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.85'; }}
        onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; }}
      >
        {checkoutLoading ? 'Redirecting...' : 'Upgrade'}
      </button>

      {/* Dismiss X */}
      <button
        onClick={dismiss}
        style={{
          background: 'none', border: 'none', cursor: 'pointer',
          color: T.textSec, fontSize: 16, lineHeight: 1, padding: 4,
          opacity: 0.4,
        }}
        aria-label="Dismiss"
      >
        &#10005;
      </button>
    </div>
  );
}

export { UPSELL_PRESETS };
